package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetAllowMissingColumnNames() throws IOException {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        boolean expected = false;

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(expected, result);
    }

    @Test
    public void testGetAllowMissingColumnNamesWithMock() throws IOException {
        // Given
        CSVFormat csvFormat = mock(CSVFormat.class);
        when(csvFormat.getAllowMissingColumnNames()).thenReturn(true);
        boolean expected = true;

        // When
        boolean result = csvFormat.getAllowMissingColumnNames();

        // Then
        assertEquals(expected, result);
    }

}
